const items = $input.all();

let metadatos = {
    fecha: "NO_DETECTADA",
    hora: "NO_DETECTADA",
    asunto: "NO_DETECTADO"
};

let totalNombres = 0;
let totalVotos = 0;
let totalExitosos = 0;
const votosGlobales = [];

items.forEach(item => {
    const data = item.json;

    if (data.asunto || data.fecha) {
        metadatos.fecha = data.fecha || metadatos.fecha;
        metadatos.hora = data.hora || metadatos.hora;
        metadatos.asunto = data.asunto || metadatos.asunto;
    }

    if (data.votos_estructurados && Array.isArray(data.votos_estructurados)) {
        votosGlobales.push(...data.votos_estructurados);

        if (data.auditoria) {
            totalNombres += data.auditoria.nombres_totales || data.auditoria.total_nombres_detectados || 0;
            totalVotos += data.auditoria.votos_sueltos_leidos || data.auditoria.total_votos_detectados || 0;
            totalExitosos += data.auditoria.registros_exitosos || 0;
        }
    }
});

return [{
    json: {
        informacion_votacion: metadatos,
        auditoria_global: {
            total_nombres_detectados: totalNombres,
            total_votos_detectados: totalVotos,
            registros_exitosos: totalExitosos
        },
        votos_estructurados_global: votosGlobales
    }
}];

const lineasCrudas = $input.first().json.ParsedResults[0].TextOverlay.Lines;

const regexVoto = /^(SI|NO|ABST\.?|AUS|LO|LE|LP|L25A|SUS|F|SIN\s?RES|\*{3,})$/i;
const regexSoloSimbolos = /^[\+\-\s]+$/;
const regexPegado = /^(.*?)\s+(SI|NO|ABST\.?|AUS|LO|LE|LP|L25A|SUS|F|SIN\s?RES|\*{3,})$/i;

let umbralY = 999999; 

for (let i = 0; i < lineasCrudas.length; i++) {
    let texto = lineasCrudas[i].LineText.replace(/[\+\-]+/g, '').trim();

    if (regexVoto.test(texto) || regexPegado.test(texto)) {
        if (lineasCrudas[i].MinTop < umbralY) {
            umbralY = lineasCrudas[i].MinTop;
        }
    }
}

umbralY = umbralY - 20;

const nombres = [];
const votosSincronizados = []; 
const votosSueltos = [];
let lineasDescartadas = 0;

lineasCrudas.forEach(lineaObj => {
    if (lineaObj.MinTop < umbralY) {
        lineasDescartadas++;
        return;
    }

    let texto = lineaObj.LineText.replace(/[\+\-]+/g, '').trim();

    if (regexSoloSimbolos.test(texto)) return;

    const matchPegado = texto.match(regexPegado);

    if (matchPegado && matchPegado[1].trim().length > 3) {
        nombres.push(matchPegado[1].trim());
        let votoP = matchPegado[2].toUpperCase().replace(/\s/g, '');
        votosSincronizados.push(votoP.includes('***') ? "ES PRESIDENTE" : votoP);
    } else {
        const matchVoto = texto.match(regexVoto);

        if (matchVoto) {
            let votoS = matchVoto[1].toUpperCase().replace(/\s/g, '');
            votosSueltos.push(votoS.includes('***') ? "ES PRESIDENTE" : votoS);
        } else if (texto.length > 3) {
            nombres.push(texto);
            votosSincronizados.push(null);
        }
    }
});

let indiceSuelto = 0;
for (let i = 0; i < votosSincronizados.length; i++) {
    if (votosSincronizados[i] === null) {
        if (indiceSuelto < votosSueltos.length) {
            votosSincronizados[i] = votosSueltos[indiceSuelto];
            indiceSuelto++;
        } else {
            votosSincronizados[i] = "NO_DETECTADO"; 
        }
    }
}

const resultados = [];
for (let i = 0; i < nombres.length; i++) {
    resultados.push({
        congresista: nombres[i],
        voto: votosSincronizados[i]
    });
}

return [{
    json: {
        auditoria: {
            techo_geometrico_real: umbralY + 20,
            margen_seguridad_aplicado: umbralY,
            lineas_basura_descartadas: lineasDescartadas,
            nombres_totales: nombres.length,
            votos_sueltos_leidos: votosSueltos.length,
            votos_pegados_leidos: votosSincronizados.filter(v => v !== null && v !== "NO_DETECTADO").length - votosSueltos.length,
            registros_exitosos: resultados.length
        },
        votos_estructurados: resultados
    }
}];

