let umbralY = 999999; 

// Encontrar el techo geometrico de los votos
for (let i = 0; i < lineasCrudas.length; i++) {
    let texto = lineasCrudas[i].LineText.replace(/[\+\-]+/g, '').trim();

    if (regexVoto.test(texto) || regexPegado.test(texto)) {
        if (lineasCrudas[i].MinTop < umbralY) {
            umbralY = lineasCrudas[i].MinTop;
        }
    }
}

// Aplicamos el margen de seguridad hacia arriba
if (umbralY !== 999999) {
    umbralY = umbralY - 15;
}

// Reconstruir el texto de la cabecera ignorando lo que este debajo del umbral
let textoCabeceraLimpio = "";
lineasCrudas.forEach(lineaObj => {
    if (lineaObj.MinTop < umbralY) {
        textoCabeceraLimpio += lineaObj.LineText + "\n";
    }
});

// Extraer los metadatos del texto limpio
const regexFecha = /Fecha:\s*([\d/]+)/i;
const regexHora = /Hora:\s*([\d:\s]+[am|pm|AM|PM]*)/i;
const regexAsunto = /Asunto:\s*([\s\S]*)/i;

const matchFecha = textoCabeceraLimpio.match(regexFecha);
const matchHora = textoCabeceraLimpio.match(regexHora);
const matchAsunto = textoCabeceraLimpio.match(regexAsunto);

const esVotacion = regexAsunto.test(textoCabeceraLimpio) || textoCabeceraLimpio.toLowerCase().includes("asunto");

const fecha = matchFecha ? matchFecha[1].trim() : "NO_DETECTADA";
const hora = matchHora ? matchHora[1].trim() : "NO_DETECTADA";

let asunto = matchAsunto ? matchAsunto[1].trim() : "NO_DETECTADO";
asunto = asunto.replace(/\n/g, ' ').trim();

return [{
    json: {
        es_votacion: esVotacion,
        fecha: fecha,
        hora: hora,
        asunto: asunto
    }
}];

const votacionId = $input.first().json.id;

const votos = $('Code in JavaScript').first().json.votos_estructurados_global;

const itemsInsertar = votos.map(registro => {
    return {
        json: {
            votacion_id: votacionId,
            congresista: registro.congresista,
            voto: registro.voto
        }
    };
});

